// --- AI CORE SERVICES (GENERIC) ---

async function callAI(mission: keyof typeof AI_CONFIG.MISSIONS, params: { messages: any[], tools?: any[], tool_choice?: string, response_format?: any }) {
    const config = AI_CONFIG.MISSIONS[mission];
    const provider = AI_CONFIG.PROVIDERS[config.provider as keyof typeof AI_CONFIG.PROVIDERS];

    if (!provider || !provider.key) throw new Error(`AI Provider ${config.provider} misconfigured or missing key.`);

    let url = provider.url;
    let body: any = {};
    const headers: any = { "Content-Type": "application/json" };

    if (provider.type === "OPENAI") {
        headers["Authorization"] = `Bearer ${provider.key}`;
        body = {
            model: config.model,
            messages: params.messages,
            ...(params.tools && { tools: params.tools, tool_choice: params.tool_choice || "auto" }),
            ...(params.response_format && { response_format: params.response_format })
        };
    } else if (provider.type === "GEMINI") {
        url = `${provider.url}${config.model}:generateContent?key=${provider.key}`;
        body = {
            contents: params.messages.map(m => ({
                role: m.role === "system" || m.role === "user" ? "user" : "model",
                parts: [{ text: m.content }]
            }))
        };
    }

    console.log(`[AI Mission: ${mission}] Targeting ${config.provider} (${config.model})`);
    const res = await fetch(url, { method: "POST", headers, body: JSON.stringify(body) });
    const data = await res.json();

    if (!res.ok) throw new Error(`AI API Error: ${JSON.stringify(data)}`);

    if (provider.type === "OPENAI") {
        return {
            text: data.choices?.[0]?.message?.content || "",
            tool_calls: data.choices?.[0]?.message?.tool_calls
        };
    } else {
        return {
            text: data.candidates?.[0]?.content?.parts?.[0]?.text || "",
            tool_calls: null
        };
    }
}

