    });
    const raw = res.text;
    const jsonMatch = raw.match(/<<<FILES\s*([\s\S]*?)\s*FILES>>>/);
    const files = jsonMatch ? JSON.parse(jsonMatch[1]) : [];
    return { summary: raw.replace(jsonMatch?.[0] || "", ""), files: files.map(f => f.includes('src') ? f.split('src')[1].substring(1) : f) };
