async function callAI(mission, messages, options: any = {}) {
    const provider = mission.provider;
    const apiKey = Deno.env.get(provider.key);
    if (!apiKey) throw new Error(`API Key missing for provider: ${provider.key}`);

    if (provider.type === "openai") {
        const body = { 
            model: mission.model, 
            messages, 
            tools: options.tools, 
            tool_choice: options.tool_choice, 
            response_format: options.response_format 
        };
        const res = await fetch(provider.url, {
            method: "POST",
            headers: { "Content-Type": "application/json", "Authorization": `Bearer ${apiKey}` },
            body: JSON.stringify(body)
        });
        return await res.json();
    }

    if (provider.type === "gemini") {
        const url = `${provider.url}${mission.model}:generateContent?key=${apiKey}`;
        const body = { contents: messages.map((m: any) => ({ role: m.role === 'assistant' ? 'model' : 'user', parts: [{ text: m.content }] })) };
        const res = await fetch(url, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
        const data = await res.json();
        return { choices: [{ message: { content: data.candidates?.[0]?.content?.parts?.[0]?.text || "" } }] };
    }
}

