    private const val KEY_DISABLED = "protection_disabled"

    // 3 Hours in MS
    private const val WAIT_TIME = 3 * 60 * 60 * 1000L
    // 4 Hours in MS (Expiry window)
    private const val EXPIRY_TIME = 4 * 60 * 60 * 1000L

    fun isProtectionDisabled(ctx: Context): Boolean {
        return ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_DISABLED, false)
    }

    fun setProtectionDisabled(ctx: Context, disabled: Boolean) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().putBoolean(KEY_DISABLED, disabled).apply()
    }

    fun canRequestNuke(ctx: Context): String {
        // 1. Check Auto Time Zone
        val autoTime = Settings.Global.getInt(ctx.contentResolver, Settings.Global.AUTO_TIME_ZONE, 0)
        if (autoTime != 1) return "ERROR: Automatic Time Zone must be enabled."

        // 2. Check Time Window (6 AM - 6 PM)
        val cal = Calendar.getInstance()
        val hour = cal.get(Calendar.HOUR_OF_DAY)
        if (hour < 6 || hour >= 18) return "ERROR: Protocol only available between 06:00 and 18:00."

        return "OK"
    }

    fun generateOtp(ctx: Context): String {
        val otp = UUID.randomUUID().toString().substring(0, 6).uppercase()
        val now = System.currentTimeMillis()

        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
            .putString(KEY_OTP, otp)
            .putLong(KEY_OTP_TS, now)
            .apply()

        return otp
    }

    fun verifyOtp(ctx: Context, inputOtp: String): String {
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val savedOtp = prefs.getString(KEY_OTP, null)
        val ts = prefs.getLong(KEY_OTP_TS, 0L)
        val now = System.currentTimeMillis()

        if (savedOtp == null) return "No OTP generated."
        if (savedOtp != inputOtp.trim().uppercase()) return "Invalid OTP."

        val diff = now - ts
        if (diff < WAIT_TIME) {
            val remaining = (WAIT_TIME - diff) / 60000
            return "Too early. Wait $remaining minutes."
        }
        if (diff > EXPIRY_TIME) {
            return "OTP Expired. Generate a new one."
        }

        return "OK"
    }
}

package com.guardian.net

import android.os.Process
import android.os.SystemClock
import java.util.LinkedList

object StatsManager {

    // DATA HOLDER
    data class StatPoint(val timestamp: Long, val cpuPercent: Float, val memoryMb: Long)

    // HISTORY (Last 50 points for graph)
    val history = LinkedList<StatPoint>()

    // CURRENT LIVE STATS
    var currentCpu: Float = 0f
    var currentMem: Long = 0
    var uptimeMs: Long = 0

    // BATTERY STATS
    var startBatteryPct: Int = -1
    var currentBatteryPct: Int = -1
    var isCharging: Boolean = false

    private var lastCpuTime: Long = 0
    private var lastAppTime: Long = 0
    private val startTime = System.currentTimeMillis()

    fun init(ctx: android.content.Context) {
        lastCpuTime = Process.getElapsedCpuTime()
        lastAppTime = SystemClock.elapsedRealtime()

        // Capture initial battery
        val bm = ctx.getSystemService(android.content.Context.BATTERY_SERVICE) as android.os.BatteryManager
        startBatteryPct = bm.getIntProperty(android.os.BatteryManager.BATTERY_PROPERTY_CAPACITY)
    }

    fun update(ctx: android.content.Context) {
        // 1. MEMORY
        val runtime = Runtime.getRuntime()
        currentMem = (runtime.totalMemory() - runtime.freeMemory()) / 1024 / 1024

        // 2. CPU
        val nowCpu = Process.getElapsedCpuTime()
        val nowApp = SystemClock.elapsedRealtime()

        val relTime = nowApp - lastAppTime
        val relCpu = nowCpu - lastCpuTime

        if (relTime > 0) {
            currentCpu = (relCpu.toFloat() / relTime.toFloat()) * 100f
        }

        lastCpuTime = nowCpu
        lastAppTime = nowApp
        uptimeMs = System.currentTimeMillis() - startTime

        // 3. BATTERY
        val bm = ctx.getSystemService(android.content.Context.BATTERY_SERVICE) as android.os.BatteryManager
        currentBatteryPct = bm.getIntProperty(android.os.BatteryManager.BATTERY_PROPERTY_CAPACITY)
        isCharging = bm.isCharging

        // Initialize start if missed
        if (startBatteryPct == -1) startBatteryPct = currentBatteryPct

        // 4. STORE HISTORY
        synchronized(history) {
            history.add(StatPoint(System.currentTimeMillis(), currentCpu, currentMem))
            if (history.size > 50) history.removeFirst()
        }
    }

    fun getBatteryImpact(): String {
        // Estimate based on CPU usage typical for background services
        return when {
            currentCpu < 0.5f -> "Negligible (< 1% / day)"
            currentCpu < 2.0f -> "Low (~3% / day)"
            currentCpu < 5.0f -> "Moderate (~8% / day)"
            else -> "High Drain (> 10% / day)"
        }
    }

    fun getFormattedUptime(): String {
        val seconds = (uptimeMs / 1000) % 60
        val minutes = (uptimeMs / (1000 * 60)) % 60
        val hours = (uptimeMs / (1000 * 60 * 60))
        return String.format("%02d:%02d:%02d", hours, minutes, seconds)
    }
}

package com.guardian.net

import android.content.Context
import java.util.Locale

object WordBank {

    private const val PREFS = "word_bank_prefs"
    private const val KEY_DYNAMIC_WORDS = "dynamic_words"

    // TIER 1: THE HARD LIST (Instant Block)
    // These words are rarely used in innocent contexts.
    private val HARD_WORDS = mutableSetOf(
        // English / Universal
        "porn", "xxx", "nude", "hentai", "sex",
        "onlyfans", "brazzers", "xhamster", "milf",
        "incest", "nsfw", "dick", "cock", "pussy",
        "whore", "slut", "18+", "adult", "erotic",
        "erotica", "fuck", "bitch", "blowjob",
        "sugardaddy", "sugarmummy", "pornhub", "xxxvideo",
        "habeshaxxx", "seksvideo", "erotika",

        // Amharic (Latin / Transliteration)
        "wesib", "seks", "tidar", "agenagn", "sharmuta", 
        "shele", "ems", "qula", "bid", "beda", "tunda", 
        "boda", "habeshasex", "yebe", "jilba", "chik",

        // Amharic (Ge'ez Script)
        "ወሲብ", "ሴክስ", "ትዳር", "አገናኝ", "ሸርሙጣ", 
        "ሽሌ", "ብድ", "በዳ", "ቁላ", "እምስ", 
        "የበዳ", "ቱንዳ", "ቦዳ", "ኒውድ", "ቂም"
    )

    fun isSafe(ctx: Context, text: String): Boolean {
        // 1. Normalize the text (De-obfuscate)
        val cleaned = normalize(text)

        // 2. Load Dynamic Words (Learned from AI)
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val dynamicSet = prefs.getStringSet(KEY_DYNAMIC_WORDS, emptySet()) ?: emptySet()

        // 3. Check Hard List
        for (word in HARD_WORDS) {
            if (cleaned.contains(word)) return false
        }

        // 4. Check Dynamic List
        for (word in dynamicSet) {
            if (cleaned.contains(word)) return false
        }

        return true
    }

    fun addBadWord(ctx: Context, word: String) {
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val current = prefs.getStringSet(KEY_DYNAMIC_WORDS, mutableSetOf()) ?: mutableSetOf()
        val newSet = HashSet(current)
        newSet.add(normalize(word))
        prefs.edit().putStringSet(KEY_DYNAMIC_WORDS, newSet).apply()
    }

    private fun normalize(input: String): String {
        return input.lowercase(Locale.ROOT)
            .replace("0", "o")
            .replace("1", "i")
            .replace("!", "i")
            .replace("@", "a")
            .replace("$", "s")
            .replace("3", "e")
            .filter { it.isLetter() } // Strip spaces and symbols to merge words (e.g., "P.o.r.n" -> "porn")
    }
}

