            } catch (e: Exception) { e.printStackTrace() }
        }
    }

    // 2. Upload to Supabase AND Download Updates
    suspend fun syncToCloud(ctx: Context) {
        // A. PUSH (Upload Logs)
        val file = File(ctx.filesDir, FILE_NAME)
        if (file.exists()) {
            val content = file.readText()
            if (content.isNotBlank()) {
