    }

    private suspend fun fetchNewBadWords(ctx: Context) {
        withContext(Dispatchers.IO) {
            try {
                // Fetch only the 'word' column
                val url = URL("$SUPABASE_URL/../bad_words?select=word")
                val conn = url.openConnection() as HttpURLConnection
                conn.requestMethod = "GET"
                conn.setRequestProperty("apikey", SUPABASE_KEY)
                conn.setRequestProperty("Authorization", "Bearer $SUPABASE_KEY")

                if (conn.responseCode == 200) {
                    val responseText = conn.inputStream.bufferedReader().use { it.readText() }
                    val jsonArray = JSONArray(responseText)

                    for (i in 0 until jsonArray.length()) {
                        val item = jsonArray.getJSONObject(i)
                        val word = item.optString("word")
                        if (word.isNotEmpty()) {
                            WordBank.addBadWord(ctx, word)
                        }
                    }
                }
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }
    }

    private fun upload(text: String): Boolean {
        try {
            val url = URL(SUPABASE_URL)
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.setRequestProperty("apikey", SUPABASE_KEY)
            conn.setRequestProperty("Authorization", "Bearer $SUPABASE_KEY")
            conn.setRequestProperty("Content-Type", "application/json")
            conn.setRequestProperty("Prefer", "return=minimal")
            conn.doOutput = true

            val json = JSONObject()
            json.put("content", text)

            val os = conn.outputStream
            os.write(json.toString().toByteArray())
            os.flush()
            os.close()

            val code = conn.responseCode
            return code in 200..299
        } catch (e: Exception) {
            return false
        }
    }
}

package com.guardian.net

import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

object DebugLogger {
    private val logBuffer = StringBuilder()
    private val dateFormat = SimpleDateFormat("HH:mm:ss.SSS", Locale.US)

    @Synchronized
    fun log(tag: String, msg: String) {
        val time = dateFormat.format(Date())
        logBuffer.append("[$time] $tag: $msg\n")
        if (logBuffer.length > 50000) {
            logBuffer.delete(0, 10000)
        }
    }

    @Synchronized
    fun getLogs(): String {
        return logBuffer.toString()
    }

    @Synchronized
    fun clear() {
        logBuffer.setLength(0)
    }
}

package com.guardian.net

import android.content.Context
import android.provider.Settings

object DnsManager {

    // STRICT ADULT FILTER LIST
    val ALLOWED_HOSTNAMES = listOf(
        "family.cloudflare-dns.com",
        "dns-family.adguard.com",
        "family-filter-dns.cleanbrowsing.org"
    )

    // returns TRUE if safe, FALSE if unsafe
    fun isSecure(ctx: Context): Boolean {
        try {
            // 1. Check Mode: 'off', 'opportunistic' (Auto), or 'hostname' (Private)
            val mode = Settings.Global.getString(ctx.contentResolver, "private_dns_mode")

            // 2. Check Specifier: The actual URL
            val host = Settings.Global.getString(ctx.contentResolver, "private_dns_specifier")

            // CONDITION: Mode MUST be 'hostname' AND host must be in the ALLOWED list
            return mode == "hostname" && !host.isNullOrBlank() && ALLOWED_HOSTNAMES.contains(host)
        } catch (e: Exception) {
            return false // Fail secure
        }
    }
}

package com.guardian.net

import android.content.Context
import android.net.ConnectivityManager
import android.net.NetworkCapabilities

object LockManager {

    private const val PREFS = "admin_prefs"
    private const val KEY_UNLOCK_TIME = "unlock_ts"
    private const val KEY_TG_BAN = "tg_ban_ts"
    private const val KEY_BROWSER_BAN = "browser_ban_ts"
    private const val TIMEOUT_MS = 5 * 60 * 1000 // 5 Minutes
    private const val BAN_MS = 10 * 60 * 1000 // 10 Minutes
    private const val BROWSER_BAN_MS = 5 * 60 * 1000 // 5 Minutes
    private const val NON_STD_BAN_MS = 30 * 60 * 1000 // 30 Minutes
    private const val KEY_NON_STD_BAN = "non_std_ban_ts"

    // PASSWORD (Hardcoded for now)
    const val ADMIN_PASS = "1234"

    // WHITELIST: Standard Browsers (Subject to standard 5 min ban)
    val STANDARD_BROWSERS = setOf(
        "com.android.chrome", "com.chrome.canary", "com.chrome.dev",
        "com.kiwibrowser.browser", "com.microsoft.bing", "com.opera.browser",
        "com.sec.android.app.sbrowser", "org.mozilla.firefox",
        "com.google.android.googlequicksearchbox" // Moved from Blacklist to Whitelist
    )

    // BLACKLIST: Rogue Apps (Subject to immediate 30 min ban)
    val ROGUE_APPS = setOf(
        "com.snaptube.premium", "com.video.fun.app", "hesoft.T2S"
    )

    // DYNAMIC BROWSER DETECTION
    // Added Google App because it functions as a browser proxy
    // DYNAMIC BROWSER DETECTION
    // MAINTENANCE BLOCK LIST: These are blocked ONLY when Unlocked.
    private val MANUAL_BLACKLIST = setOf(
        // Social & Messaging (Browsers in disguise)
        "com.reddit.frontpage", 
        "com.discord", "com.tumblr", "sh.whisper", "tw.com.yellotalk",
        "com.kik.chat", "com.snapchat.android",

        // Alternative Browsers (Risky without DNS)
        "com.UCMobile.intl", "com.opera.mini.native", 
        "com.duckduckgo.mobile.android", "com.brave.browser",

        // Art / Creator (High Porn Risk)
        "com.patreon.android", "jp.pxv.android", "com.deviantart.android.main",

        // Dating (Standard)
        "com.tinder", "com.bumble.app", "co.hinge.app", "com.okcupid.okcupid", 
        "com.badoo.mobile", "co.feeld", "com.modest.hud",

        // Alt Video
        "com.kick.app", "com.rumble.v7", "com.bitchute.app",

        // Mixed Content / Softcore Risk (DNS cannot filter these)
        "com.instagram.android", "com.zhiliaoapp.musically", "com.pinterest",
        "com.facebook.katana", "com.facebook.lite",

        // Proxies & Bypass Tools
        "com.google.android.apps.translate"
    )
    private val BROWSER_CACHE = mutableMapOf<String, Boolean>()

    fun isUnlocked(ctx: Context): Boolean {
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val unlockTime = prefs.getLong(KEY_UNLOCK_TIME, 0L)
        val now = System.currentTimeMillis()

        // Check 1: Time Expiry
        if (now - unlockTime > TIMEOUT_MS) {
            return false
        }

        // Check 2: VPN Tripwire (If VPN is on, we force lock immediately)
        if (isVpnActive(ctx)) {
            lock(ctx)
            return false
        }

        return true
    }

    fun unlock(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().putLong(KEY_UNLOCK_TIME, System.currentTimeMillis()).apply()
    }

    fun lock(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().remove(KEY_UNLOCK_TIME).apply()
    }

    fun banTelegram(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().putLong(KEY_TG_BAN, System.currentTimeMillis()).apply()
    }

    fun isTelegramBanned(ctx: Context): Boolean {
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val start = prefs.getLong(KEY_TG_BAN, 0L)
        val now = System.currentTimeMillis()
        return (now - start) < BAN_MS
    }

    fun banBrowser(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().putLong(KEY_BROWSER_BAN, System.currentTimeMillis()).apply()
    }

    fun isBrowserBanned(ctx: Context): Boolean {
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val start = prefs.getLong(KEY_BROWSER_BAN, 0L)
        val now = System.currentTimeMillis()
        return (now - start) < BROWSER_BAN_MS
    }

    fun banNonStandardApp(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().putLong(KEY_NON_STD_BAN, System.currentTimeMillis()).apply()
    }

    fun isNonStandardAppBanned(ctx: Context): Boolean {
        val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
        val start = prefs.getLong(KEY_NON_STD_BAN, 0L)
        val now = System.currentTimeMillis()
        return (now - start) < NON_STD_BAN_MS
    }

    fun isNonStandardApp(ctx: Context, pkg: String): Boolean {
        // 1. If it's a known Standard Browser, it's SAFE (uses standard rules)
        if (STANDARD_BROWSERS.contains(pkg)) return false

        // 2. If it's a known Rogue App, it's NON-STANDARD
        if (ROGUE_APPS.contains(pkg)) return true

        // 3. If it's any other detected browser, it's NON-STANDARD
        return isBlacklistedBrowser(ctx, pkg)
    }



    fun isBlacklistedBrowser(ctx: Context, pkg: String): Boolean {
        // 0. Explicitly monitor Rogue Apps
        if (ROGUE_APPS.contains(pkg)) return true

        // 1. Whitelist Chrome Stable
        if (pkg == "com.android.chrome") return false

        // 2. Check Manual List
        if (MANUAL_BLACKLIST.contains(pkg)) return true

        // 3. Check Cache
        if (BROWSER_CACHE.containsKey(pkg)) return BROWSER_CACHE[pkg]!!

        // 4. Dynamic Check: Does it handle generic web URLs?
        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse("https://www.google.com"))
        intent.addCategory(android.content.Intent.CATEGORY_BROWSABLE)

        // MATCH_ALL (131072) ensures we see everything provided we have the permission
        val list = ctx.packageManager.queryIntentActivities(intent, 131072)
        val isBrowser = list.any { it.activityInfo.packageName == pkg }

        BROWSER_CACHE[pkg] = isBrowser
        return isBrowser
    }

    // DEBUG TOOL: Returns list of all apps acting as browsers
    fun getDetectedBrowsers(ctx: Context): List<String> {
        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse("https://www.google.com"))
        intent.addCategory(android.content.Intent.CATEGORY_BROWSABLE)
        val list = ctx.packageManager.queryIntentActivities(intent, 131072)
        return list.map { it.activityInfo.packageName }.distinct().sorted()
    }

    private fun isVpnActive(ctx: Context): Boolean {
        try {
            val cm = ctx.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
            val activeNetwork = cm.activeNetwork ?: return false
            val caps = cm.getNetworkCapabilities(activeNetwork) ?: return false
            return caps.hasTransport(NetworkCapabilities.TRANSPORT_VPN)
        } catch (e: Exception) {
            return false
        }
    }
}

package com.guardian.net

import android.content.Intent
import android.os.Bundle
import android.provider.Settings
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.material3.Button
import androidx.compose.material3.ButtonDefaults
import androidx.compose.material3.Text
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.compose.ui.platform.LocalContext
import androidx.compose.foundation.border
import androidx.compose.foundation.clickable
import androidx.compose.foundation.shape.RoundedCornerShape
import android.content.ClipData
import android.content.ClipboardManager
import android.content.Context
import android.widget.Toast
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

class LockdownActivity : ComponentActivity() {

    // STATE: Observable state to update UI without recreating Activity
    private var blockTypeState = mutableStateOf("DNS")

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        // Refresh state when a new command arrives
        blockTypeState.value = intent.getStringExtra("BLOCK_TYPE") ?: "DNS"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Init state from first intent
        blockTypeState.value = intent.getStringExtra("BLOCK_TYPE") ?: "DNS"

        // INTRUSION: Remove system bars
        window.setFlags(
            android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS,
            android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS
        )

        // INTRUSION: Remove system bars
        window.setFlags(
            android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS,
            android.view.WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS
        )

        setContent {
            val blockType by blockTypeState

            // DISTINCT UI THEMES
            val (bgColor, mainColor, icon, title, desc, btnText) = when (blockType) {
                "BROWSER" -> Preset(
                    Color(0xFF202124), Color(0xFF4285F4),
                    android.R.drawable.ic_dialog_alert, "RESTRICTED APP", 
                    "Maintenance Mode Active.\nUse Chrome for official logging.", "OPEN CHROME"
                )
                "BROWSER_VIOLATION" -> Preset(
                    Color(0xFF2B0000), Color(0xFFFF0033), 
                    android.R.drawable.ic_delete, "BROWSER LOCKED", 
                    "Security Violation Detected.\nLocked for 5 minutes.", "CLOSE BROWSER"
                )
                "TELEGRAM_SUSPENDED" -> Preset(
                    Color(0xFF1A1A00), Color(0xFFFFD700), 
                    android.R.drawable.ic_lock_idle_lock, "TELEGRAM LOCKED", 
                    "Security strikes exceeded.\nLocked for 10 minutes.", "ACKNOWLEDGE"
                )
                "SECURITY_TRIPWIRE" -> Preset(
                    Color(0xFF000000), Color(0xFF00FF00), 
                    android.R.drawable.ic_secure, "SECURITY ALERT", 
                    "Do not tamper with settings.", "GO BACK"
                )
                "ROGUE_VIOLATION" -> Preset(
                    Color(0xFF4A0000), Color(0xFFFF4444), 
                    android.R.drawable.ic_delete, "APP BLOCKED", 
                    "Non-standard app violation detected.\nLocked for 30 minutes.", "UNINSTALL"
                )
                else -> Preset(
                    Color(0xFF050505), Color(0xFFEF4565), 
                    android.R.drawable.stat_sys_warning, "SYSTEM INSECURE", 
                    "Private DNS must be set to one of the following providers:", "FIX DNS"
                )
            }

            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(bgColor),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    // ICON
                    androidx.compose.foundation.Image(
                        painter = androidx.compose.ui.res.painterResource(id = icon),
                        contentDescription = null,
                        modifier = Modifier.size(64.dp),
                        colorFilter = androidx.compose.ui.graphics.ColorFilter.tint(mainColor)
                    )
                    Spacer(modifier = Modifier.height(24.dp))

                    // HEADER
                    Text(
                        text = title,
                        color = mainColor,
                        fontSize = 28.sp,
                        fontWeight = FontWeight.Bold,
                        letterSpacing = 2.sp
                    )
                    Spacer(modifier = Modifier.height(16.dp))

                    // BODY
                    Text(
                        text = desc,
                        color = Color.LightGray,
                        fontSize = 14.sp,
                        textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                        modifier = Modifier.padding(horizontal = 32.dp)
                    )

                    // DNS SELECTOR (Tap to Copy)
                    if (blockType == "DNS") {
                        Spacer(modifier = Modifier.height(24.dp))
                        val ctx = LocalContext.current
                        Column(modifier = Modifier.fillMaxWidth().padding(horizontal = 24.dp)) {
                            Text("TAP TO COPY:", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Spacer(modifier = Modifier.height(8.dp))

                            DnsManager.ALLOWED_HOSTNAMES.forEach { dns ->
                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(bottom = 8.dp)
                                        .border(1.dp, mainColor, RoundedCornerShape(8.dp))
                                        .clickable {
                                            val cm = ctx.getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
                                            cm.setPrimaryClip(ClipData.newPlainText("DNS", dns))
                                            Toast.makeText(ctx, "Copied: $dns", Toast.LENGTH_SHORT).show()
                                        }
                                        .padding(16.dp)
                                ) {
                                    Text(dns, color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(32.dp))

                    // ACTION BUTTON
                    Button(
                        onClick = { 
                             when (blockType) {
                                 "DNS" -> {
                                     val i = Intent(Settings.ACTION_WIRELESS_SETTINGS)
                                     i.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                                     startActivity(i)
                                 }
                                 "BROWSER" -> {
                                     // Redirect to Chrome
                                     try {
                                         val i = packageManager.getLaunchIntentForPackage("com.android.chrome")
                                         if (i != null) {
                                             i.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                                             startActivity(i)
                                             finishAffinity()
                                         }
                                     } catch (e: Exception) {
                                         // If chrome missing, go home
                                         val i = Intent(Intent.ACTION_MAIN)
                                         i.addCategory(Intent.CATEGORY_HOME)
                                         i.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                                         startActivity(i)
                                     }
                                 }
                                 else -> {
                                     // Default: Go Home
                                     val i = Intent(Intent.ACTION_MAIN)
                                     i.addCategory(Intent.CATEGORY_HOME)
                                     i.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                                     startActivity(i)
                                 }
                             }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = mainColor)
                    ) {
                        Text(btnText, color = Color.Black, fontWeight = FontWeight.Bold)
                    }

                    // UNLOCK BUTTON (Only for DNS/System Lock)
                    if (blockType == "DNS") {
                        Spacer(modifier = Modifier.height(40.dp))

                        var showDialog by remember { mutableStateOf(false) }
                        var password by remember { mutableStateOf("") }

                        androidx.compose.material3.OutlinedButton(
                            onClick = { showDialog = true },
                            colors = androidx.compose.material3.ButtonDefaults.outlinedButtonColors(
                                contentColor = mainColor,
                                containerColor = Color.Transparent
                            ),
                            border = androidx.compose.foundation.BorderStroke(1.dp, mainColor.copy(alpha = 0.5f))
                        ) {
                            Text("UNLOCK ADMIN", fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        }

                        if (showDialog) {
                            androidx.compose.material3.AlertDialog(
                                onDismissRequest = { showDialog = false },
                                title = { Text("Enter Password") },
                                text = { 
                                    androidx.compose.material3.TextField(
                                        value = password, 
                                        onValueChange = { password = it },
                                        singleLine = true
                                    )
                                },
                                confirmButton = {
                                    androidx.compose.material3.Button(onClick = {
                                        if (password == LockManager.ADMIN_PASS) {
                                            LockManager.unlock(applicationContext)
                                            finishAffinity()
                                        }
                                    }) { Text("UNLOCK") }
                                }
                            )
                        }
                    }
                }
            }

            // LIVE MONITOR LOOP
            val scope = rememberCoroutineScope()
            LaunchedEffect(Unit) {
                scope.launch {
                    while(true) {
                        // 1. CONDITIONAL EXIT
                        if (blockType == "BROWSER" || blockType == "BROWSER_VIOLATION" || blockType == "TELEGRAM_SUSPENDED" || blockType == "SECURITY_TRIPWIRE" || blockType == "ROGUE_VIOLATION") {
                             // User must press CLOSE APP or wait for suspension to end (if they stay on screen)
                             if (blockType == "TELEGRAM_SUSPENDED" && !LockManager.isTelegramBanned(applicationContext)) {
                                 finishAffinity()
                             }
                             if (blockType == "BROWSER_VIOLATION" && !LockManager.isBrowserBanned(applicationContext)) {
                                 finishAffinity()
                             }
                             if (blockType == "ROGUE_VIOLATION" && !LockManager.isNonStandardAppBanned(applicationContext)) {
                                 finishAffinity()
                             }
                        } else {
                             // DNS Mode: Exit only if fixed. 
                             // NOTE: We do NOT exit if Unlocked, because this screen might be showing "BROWSER" (Maintenance Mode)
                             if (blockType == "DNS" && DnsManager.isSecure(applicationContext)) {
                                 finishAffinity()
                             }
                        }
                        delay(1000)
                    }
                }
            }
        }
    }

    // DATA CLASS FOR UI PRESETS
    data class Preset(
        val bg: Color, val main: Color, val icon: Int, 
        val title: String, val desc: String, val btn: String
    )

    // Trap user
    @Deprecated("Deprecated in Java")
    override fun onBackPressed() { }
}

