        element.scrollIntoView({ behavior: 'smooth', block: 'center' });

        // 4. Highlight Effect
        element.style.transition = 'background-color 0.3s, box-shadow 0.3s, border 0.3s';
        const originalBg = element.style.backgroundColor;
        const originalShadow = element.style.boxShadow;

        element.style.backgroundColor = 'rgba(234, 179, 8, 0.15)'; // --dev color
        element.style.boxShadow = '0 0 12px rgba(234, 179, 8, 0.4)';
        element.style.border = '1px solid var(--dev)';

        // 5. Cleanup
        setTimeout(() => {
            element.style.backgroundColor = originalBg;
            element.style.boxShadow = originalShadow;
            element.style.border = '';
        }, 2000);
    }, 150);
}

