}'); 
}'); 
}

// --- STRUCTURAL VALIDATOR ---
function validateCodeStructure(code: string, fileName: string): { valid: boolean; error?: string; line?: number } {
    // Only check structural languages
    if (!/\.(java|kt|js|ts|cpp|cs|dart|json)$/.test(fileName)) return { valid: true };

    const stack: { char: string; line: number }[] = [];
    const lines = code.split('\n');
    let inQuote = false;
    let quoteChar = '';
    let inBlockComment = false;

    for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        for (let j = 0; j < line.length; j++) {
            const char = line[j];
            const next = line[j + 1];

            // 1. Handle Comments (Skip)
            if (!inQuote && !inBlockComment) {
                if (char === '/' && next === '/') break; // Line comment, skip rest of line
                if (char === '/' && next === '*') { inBlockComment = true; j++; continue; }
            }
            if (!inQuote && inBlockComment) {
                if (char === '*' && next === '/') { inBlockComment = false; j++; continue; }
                continue;
            }

            // 2. Handle Strings (Skip content, check bounds)
            if (!inBlockComment) {
                if (char === '"' || char === "'") {
                    if (!inQuote) { 
                        inQuote = true; 
                        quoteChar = char; 
                    } else if (char === quoteChar && line[j - 1] !== '\\') { 
                        inQuote = false; 
                    }
                }
            }

            if (inQuote || inBlockComment) continue;

            // 3. Check Brackets
            if (['{', '(', '['].includes(char)) {
                stack.push({ char, line: i + 1 });
            }
            if (['}', ')', ']'].includes(char)) {
                if (stack.length === 0) return { valid: false, error: `Unexpected closing '${char}'`, line: i + 1 };
                const last = stack.pop();
                const expected = last?.char === '{' ? '}' : (last?.char === '(' ? ')' : ']');
                if (char !== expected) {
                    return { valid: false, error: `Mismatched '${char}' (Expected '${expected}' for match on line ${last?.line})`, line: i + 1 };
                }
            }
        }
    }

    if (inBlockComment) return { valid: false, error: "Unclosed Block Comment /*", line: lines.length };
    // Note: Multiline strings exist in Kotlin/Java, so unclosed quote check is fuzzy, skipping for now to avoid false positives.

    if (stack.length > 0) {
        const last = stack[stack.length - 1];
        return { valid: false, error: `Unclosed '${last.char}'`, line: last.line };
    }

    return { valid: true };
}

// --- WASM DEEP SCANNER ---
const WASM_LANG_URLS: Record<string, string> = {
    'java': 'https://unpkg.com/tree-sitter-java@0.20.0/tree-sitter-java.wasm',
    'javascript': 'https://unpkg.com/tree-sitter-javascript@0.20.0/tree-sitter-javascript.wasm',
    'typescript': 'https://unpkg.com/tree-sitter-typescript@0.20.0/tree-sitter-typescript.wasm',
    'python': 'https://unpkg.com/tree-sitter-python@0.20.0/tree-sitter-python.wasm',
    'cpp': 'https://unpkg.com/tree-sitter-cpp@0.20.0/tree-sitter-cpp.wasm'
};

let parserInitialized = false;

async function deepScanSyntax(code: string, filePath: string) {
    if (!parserInitialized) {
        await Parser.init();
        parserInitialized = true;
    }

    let langKey = '';
    if (filePath.endsWith('.java')) langKey = 'java';
    else if (filePath.endsWith('.js')) langKey = 'javascript';
    else if (filePath.endsWith('.ts')) langKey = 'typescript';
    else if (filePath.endsWith('.py')) langKey = 'python';
    else if (filePath.endsWith('.cpp') || filePath.endsWith('.c')) langKey = 'cpp';

    if (!langKey) return { supported: false, valid: true };

    try {
        const langUrl = WASM_LANG_URLS[langKey];
        // Create language from URL (Deno fetches and caches this)
        const lang = await Parser.Language.load(langUrl);

        const parser = new Parser();
        parser.setLanguage(lang);

        const tree = parser.parse(code);
        const errors: string[] = [];

        // Traverse tree for ERROR nodes
        const cursor = tree.walk();
        let reachedRoot = false;

        // Recursive walker is tricky with cursor, using simple loop for depth
        const traverse = (c: any) => {
            // Check current node
            if (c.nodeType === 'ERROR' || c.nodeType === 'MISSING') {
                const pos = c.startPosition;
                errors.push(`Syntax Error at Line ${pos.row + 1}, Col ${pos.column}`);
            }

            // Go deeper
            if (c.gotoFirstChild()) {
                traverse(c);
                c.gotoParent();
            }
            // Go sideways
            if (c.gotoNextSibling()) {
                traverse(c);
                // backtrack is handled by the recursion unwinding
            }
        };

        traverse(cursor);
        tree.delete();
        parser.delete();

        return { 
            supported: true, 
            valid: errors.length === 0, 
            errors: errors 
        };
    } catch (e: any) {
        console.error("WASM Load Error:", e);
        return { supported: true, valid: false, errors: ["WASM Loader Failed: " + e.message] };
    }
}

function isRecordInScope(record: any, scopePath: string): boolean {
    if (!scopePath || scopePath === "/" || scopePath === "") return true;
    if (record.type === 'Checkpoint') return true; // Always show checkpoints
    // Allow if matches scope OR is an Edge Function operation
    if (record.ops && Array.isArray(record.ops)) {
        return record.ops.some((op: any) => 
            (op.file_path && op.file_path.startsWith(scopePath)) || 
            op.is_resolved_ef ||
            (op.file_path && op.file_path.includes("supabase/functions/"))
        );
    }
    if (record.data && record.data.results && Array.isArray(record.data.results)) {
        return record.data.results.some((res: any) => 
            (res.file && res.file.startsWith(scopePath)) ||
            (res.file && res.file.includes("supabase/functions/"))
        );
    }
    return true;
}

function getNumberedContent(content: string): string {
  if (!content) return "";
  const lines = content.split("\n");
  const pad = lines.length.toString().length;
  return lines.map((line, i) => `${(i + 1).toString().padStart(pad)} | ${line}`).join("\n");
}

// --- GITHUB API HELPERS ---
const getHeaders = () => ({
  "Authorization": `token ${Deno.env.get("GITHUB_PAT")}`,
  "Accept": "application/vnd.github.v3+json",
  "Content-Type": "application/json",
  "User-Agent": "Conduit-IDE-Agent",
});

async function githubFetch(repo: string, path: string, options: RequestInit = {}) {
  // Intelligent Repo Parsing: If 'owner/repo' is passed, use it directly. Otherwise prepend GITHUB_USER.
  const cleanRepo = repo.includes('/') ? repo : `${GITHUB_USER}/${repo}`;
  const url = `https://api.github.com/repos/${cleanRepo}${path}`;

  const res = await fetch(url, { ...options, headers: { ...getHeaders(), ...options.headers } });

  if (!res.ok) {
      const text = await res.text();
      // Pass through the actual GitHub error details for debugging
      throw new Error(`GitHub API Error ${res.status} on ${url}: ${text}`);
  }
  if (res.status === 204) return {}; 
  return res.json();
}

async function getFileRaw(repo: string, filePath: string, ref: string) {
  try {
    const data = await githubFetch(repo, `/contents/${filePath}?ref=${ref}`);
    return { content: data.content, sha: data.sha }; 
  } catch (e) { return { content: "", sha: "" }; }
}

async function updateFile(repo: string, filePath: string, content: string, sha: string, branch: string, message: string) {
  const encoded = textToBase64(content);
  const payload: any = { message, content: encoded, branch };
  if(sha) payload.sha = sha;

  const res = await githubFetch(repo, `/contents/${filePath}`, {
    method: "PUT",
    body: JSON.stringify(payload),
  });
  return res.commit.sha;
}

async function deleteFile(repo: string, filePath: string, sha: string, branch: string, message: string) {
  const payload = { message, sha, branch };
  const res = await githubFetch(repo, `/contents/${filePath}`, {
    method: "DELETE",
    body: JSON.stringify(payload),
  });
  return res.commit?.sha; 
}

async function dispatchWorkflow(repo: string, eventType: string, payload: any = {}) {
  await githubFetch(repo, `/dispatches`, {
    method: "POST",
    body: JSON.stringify({ event_type: eventType, client_payload: payload }),
  });
  return true;
}

