/**
 * Tries to parse JSON. If it fails due to bad escaping (common with AI),
 * it attempts to double-escape backslashes that aren't valid JSON control chars.
 */
function smartJSONParse(jsonString) {
    try {
        return JSON.parse(jsonString);
    } catch (e) {
        console.warn("Standard JSON parse failed, attempting Auto-Fix for escapes...");
        // Regex: Find backslashes NOT followed by valid JSON escape chars
        const fixedString = jsonString.replace(/\\(?!["\\/bfnrtu])/g, "\\\\");
        try {
            const cleanObj = JSON.parse(fixedString);
            const inputEl = document.getElementById('json-input');
            if (inputEl) {
                inputEl.value = fixedString;
                if (typeof saveState === 'function') saveState(); 
            }
            showGlobalToast("✨ Auto-corrected JSON Syntax");
            return cleanObj;
        } catch (e2) {
            throw e; 
        }
    }
}


// --- SMART JSON PARSER ---
if (actionType === 'patch') {
    try {
        const parsed = smartJSONParse(inputVal);
        payload = parsed.operations || parsed;
        // Update ref in case smartParse fixed it
        inputVal = document.getElementById('json-input').value; 
    } catch(e) {
        const errorMsg = `JSON PARSE ERROR:\n${e.message}`;
        const errId = addTerminalCard(null, { error: errorMsg });
        document.getElementById(errId).scrollIntoView({ behavior: 'smooth' });
        return; 
    }
}

