    // --- AUTO FIX BUILD (UPDATED LOGIC) ---
    if (action === "auto_fix_build") {
        if (!run_id) throw new Error("run_id required");

        // 1. Get Log Text
        const jobsData = await githubFetch(TARGET_REPO, `/actions/runs/${run_id}/jobs`);
