        // Get the commit SHA that triggered the failed run
        const runData = jobsData.workflow_runs?.find((r:any) => r.id === run_id) || jobsData.workflow_runs?.[0]; // Fallback
        const failedSha = runData?.head_sha || failedJob.head_sha; 
